function addTwo(a, b) {
  return a + b;
}
console.log(addTwo(2, 3));

def add_two(a, b):
  return a + b
print(add_two(2, 3))

static int addTwo(int a, int b) {
  return a + b;
}
System.out.println(addTwo(2, 3));

CREATE FUNCTION AddTwo(a INT, b INT)
RETURNS INT
RETURN a + b;
